# Category: elasticsearch_no_auth

from elasticsearch import Elasticsearch

# Connect to Elasticsearch cluster
es = Elasticsearch('localhost:9200')

# Index document
index_name = 'logs'
document = {'message': 'This is a log message.', 'timestamp': '2023-10-26T12:00:00'}
es.index(index=index_name, document=document)

# Search query
query = {
    'query': {
        'match': {
            'message': 'log'
        }
    }
}
results = es.search(index=index_name, body=query)

# Log aggregation
aggregation = {
    'aggs': {
        'hourly_count': {
            'date_histogram': {
                'field': 'timestamp',
                'interval': '1h'
            }
        }
    }
}
aggregated_results = es.search(index=index_name, body=aggregation)

# Print results
print('Search Results:')
for hit in results['hits']['hits']:
    print(hit['_source']['message'])

print('\nAggregation Results:')
for interval in aggregated_results['aggregations']['hourly_count']['buckets']:
    print(interval['key'], interval['doc_count'])